mapper.select:
SELECT
    p.id, p.line_no, p.product_name, p.product_no, p.type, p.remark, p.version, p.deploy_at, p.is_valid, p.is_delete,
    pl.value_type, pl.value
FROM product p
LEFT JOIN product_limit pl ON p.product_no = pl.product_no


        p.line_no = #{param.lineNo}


        AND p.type = #{param.type}


        AND p.product_name like CONCAT(#{param.productName}, '%')


        AND p.product_no = #{param.productNo}


        AND p.is_valid = #{param.isValid}

    AND p.is_delete = 0 AND pl.is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM product p
LEFT JOIN product_limit pl ON p.product_no = pl.product_no


        p.line_no = #{param.lineNo}


        AND p.type = #{param.type}


        AND p.product_name like CONCAT(#{param.productName}, '%')


        AND p.product_no = #{param.productNo}


        AND p.is_valid = #{param.isValid}

    AND p.is_delete = 0 AND pl.is_delete = 0
